import React, { useState } from "react";
import { MapContainer, TileLayer, CircleMarker, Marker, Popup, Tooltip } from "react-leaflet";
import { useNavigate } from "react-router-dom";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import { URGENCY_MAP_COLORS, capitalize, getInitials } from "../utils/helpers";
import { UrgencyBadge, CategoryBadge } from "../components/Badges";

delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon-2x.png",
  iconUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-icon.png",
  shadowUrl: "https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/images/marker-shadow.png",
});

export default function MapPage({ needs, volunteers, user }) {
  const navigate = useNavigate();
  const [filter, setFilter] = useState("all");
  const isAdmin = user?.role === "admin";

  const center = [28.65, 77.23];
  const filteredNeeds = filter === "all" ? needs : needs.filter((n) => n.urgency === filter);

  return (
    <div>
      <div className="filter-row" style={{ marginBottom: "1rem" }}>
        {["all", "critical", "high", "medium", "low"].map((u) => (
          <button key={u} className={`filter-chip ${filter === u ? "active" : ""}`} onClick={() => setFilter(u)}>
            {u === "all" ? "All urgency" : capitalize(u) + " urgency"}
          </button>
        ))}
        <button className={`filter-chip ${showVols ? "active" : ""}`} onClick={() => setShowVols(!showVols)}>
          {showVols ? "Hide" : "Show"} Volunteers
        </button>
      </div>

      <div style={{ display: "flex", gap: 12, marginBottom: "1rem", flexWrap: "wrap" }}>
        {[["Critical", "#991b1b"], ["High urgency", "#ef4444"], ["Medium", "#eab308"], ["Low", "#22c55e"], ["Volunteer", "#3b82f6"]].map(([label, color]) => (
          <div key={label} style={{ display: "flex", alignItems: "center", gap: 6, fontSize: 12, color: "#64748b" }}>
            <span style={{ width: 10, height: 10, borderRadius: "50%", background: color, flexShrink: 0 }} />
            {label}
          </div>
        ))}
      </div>

      <div style={{ borderRadius: 12, overflow: "hidden", border: "1px solid #e2e8f0", height: 480 }}>
        <MapContainer center={center} zoom={13} style={{ height: "100%", width: "100%" }}>
          <TileLayer
            attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a>'
            url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
          />
          {filteredNeeds.map((need) => (
            <CircleMarker
              key={need.id}
              center={[need.location.lat, need.location.lng]}
              radius={12}
              fillColor={URGENCY_MAP_COLORS[need.urgency]}
              color={URGENCY_MAP_COLORS[need.urgency]}
              weight={2}
              opacity={0.9}
              fillOpacity={0.6}
            >
              <Tooltip permanent={false}>{need.title}</Tooltip>
              <Popup>
                <div style={{ minWidth: 180 }}>
                  <strong>{need.title}</strong><br />
                  <div style={{ display: "flex", gap: 4, margin: "4px 0", flexWrap: "wrap" }}>
                    <UrgencyBadge urgency={need.urgency} />
                    <CategoryBadge category={need.category} />
                  </div>
                  <p style={{ margin: "4px 0", fontSize: 12 }}>{need.description}</p>
                  <p style={{ margin: 0, fontSize: 12, color: "#64748b" }}>👥 {need.peopleAffected} affected</p>

                  {isAdmin && need.status !== "completed" && need.status !== "rejected" && (
                    <button 
                      className="btn btn-sm btn-primary" 
                      style={{ width: "100%", marginTop: 10, fontSize: 11 }}
                      onClick={() => navigate(`/matching/${need.id}`)}
                    >
                      Assign Volunteer
                    </button>
                  )}
                </div>
              </Popup>
            </CircleMarker>
          ))}
          {showVols && volunteers.map((vol) => (
            <CircleMarker
              key={vol.id}
              center={[vol.location.lat, vol.location.lng]}
              radius={8}
              fillColor="#3b82f6"
              color="#1d4ed8"
              weight={2}
              opacity={vol.availability ? 1 : 0.4}
              fillOpacity={vol.availability ? 0.8 : 0.3}
            >
              <Popup>
                <strong>{vol.name}</strong><br />
                <span style={{ fontSize: 12 }}>{vol.availability ? "✅ Available" : "⏸ Unavailable"}</span><br />
                <span style={{ fontSize: 12 }}>Skills: {vol.skills.join(", ")}</span>
              </Popup>
            </CircleMarker>
          ))}
        </MapContainer>
      </div>

      <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: 8, marginTop: "1rem" }}>
        {["critical", "high", "medium", "low"].map((u) => (
          <div key={u} className="metric-card">
            <div className="metric-label">{capitalize(u)} urgency</div>
            <div className="metric-value" style={{ color: URGENCY_MAP_COLORS[u], fontSize: 22 }}>
              {needs.filter((n) => n.urgency === u).length}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
